#!/usr/bin/env python3
# =========================================================
#  هذا الملف مشفّر بواسطة أداة GORDON
#  مستوى التشفير: قوي جدًا (Maximum)
#  لتشغيله تحتاج ملف المفتاح (.gordonkey) بنفس المجلد
#  أو مرره عبر: python3 instagram_brute_protected.py --key path/to/keyfile
# =========================================================
import base64, os, sys, argparse
from cryptography.fernet import Fernet
from cryptography.hazmat.primitives import hashes
from cryptography.hazmat.primitives.kdf.pbkdf2 import PBKDF2HMAC

_PAYLOAD = ""
_LAYERS = 3
_ITERATIONS = 1200000
_DEFAULT_KEY_NAME = "instagram_brute.gordonkey"

def _derive_key(secret, salt, iterations):
    kdf = PBKDF2HMAC(algorithm=hashes.SHA256(), length=32, salt=salt, iterations=iterations)
    return base64.urlsafe_b64encode(kdf.derive(secret))

def _run():
    parser = argparse.ArgumentParser(add_help=False)
    parser.add_argument("--key", default=None)
    args, _ = parser.parse_known_args()

    key_path = args.key or os.path.join(os.path.dirname(os.path.abspath(__file__)), _DEFAULT_KEY_NAME)
    if not os.path.isfile(key_path):
        print(f"[!] ملف المفتاح غير موجود: {key_path}")
        sys.exit(1)

    with open(key_path, "rb") as f:
        base_secret = f.read().strip()

    raw = base64.b64decode(_PAYLOAD)
    salt, encrypted = raw.split(b"::", 1)

    data = encrypted
    try:
        for i in reversed(range(_LAYERS)):
            layer_salt = bytes([b ^ (i + 1) for b in salt])
            key = _derive_key(base_secret + str(i).encode(), layer_salt, _ITERATIONS)
            data = Fernet(key).decrypt(data)
    except Exception:
        print("[!] فشل فك التشفير — مفتاح غير صحيح أو الملف تالف.")
        sys.exit(1)

    exec(compile(data, "<gordon-protected>", "exec"), {"__name__": "__main__"})

if __name__ == "__main__":
    _run()
